// BroadFSC Pro — Course Data (30 courses with full lessons & quizzes)
const COURSES=[
{id:1,title:"Stock Market Fundamentals",level:"beginner",icon:"📈",desc:"Learn how stock markets work, from exchanges to order types.",duration:"2h 30min",modules:6,
lessons:[
{t:"What Is a Stock Exchange?",d:"15min",content:"<strong>Stock exchanges</strong> are centralized marketplaces where buyers and sellers trade shares of publicly listed companies. Major exchanges: NYSE, NASDAQ, LSE, TSE, HKEX.<br><br><strong>Key Concepts:</strong><ul><li><strong>Ticker Symbol</strong> — Unique abbreviation (AAPL for Apple)</li><li><strong>Market Cap</strong> — Share price × total shares outstanding</li><li><strong>Trading Hours</strong> — NYSE: 9:30 AM–4:00 PM ET</li><li><strong>Circuit Breakers</strong> — Halt trading when indices drop 7%, 13%, or 20%</li></ul><br><strong>Why It Matters:</strong> Understanding exchange mechanics helps you time entries/exits and avoid illiquid periods."},
{t:"How Stock Prices Are Determined",d:"20min",content:"<strong>Price discovery</strong> determines fair price through supply and demand.<br><br><ul><li><strong>Order Book</strong> — Real-time list of buy (bid) and sell (ask) orders</li><li><strong>Bid-Ask Spread</strong> — Difference between highest bid and lowest ask. Narrow = high liquidity</li><li><strong>Market Orders</strong> — Execute immediately at best available price</li><li><strong>Limit Orders</strong> — Execute only at your specified price or better</li><li><strong>Stop Orders</strong> — Trigger when a specified price is reached</li></ul><br><strong>Price Impact:</strong> Large orders can move the price — this is 'slippage'. Institutional traders use algorithms to minimize it."},
{t:"Bull vs Bear Markets",d:"15min",content:"<strong>Bull Market</strong> — Sustained rising prices (+20% from lows). Optimism, strong earnings.<br><br><strong>Bear Market</strong> — Sustained decline (-20% from highs). Pessimism, recession fears.<br><br><strong>Historical Facts:</strong><ul><li>Longest bull market: 2009–2020 (11 years)</li><li>Average bear market: ~9.6 months</li><li>Bears occur on average every 5.7 years</li></ul><br><strong>Strategy:</strong> In bull markets, ride momentum. In bear markets, focus on capital preservation, defensive sectors (utilities, healthcare, consumer staples)."},
{t:"Market Indices Explained",d:"15min",content:"<strong>Major Indices:</strong><ul><li><strong>S&P 500</strong> — 500 largest US companies. Gold standard for US market.</li><li><strong>Dow Jones</strong> — 30 blue chip stocks. Price-weighted.</li><li><strong>NASDAQ</strong> — 3,000+ stocks, heavy tech.</li><li><strong>Russell 2000</strong> — Small-cap US stocks.</li><li><strong>MSCI World</strong> — Global developed market benchmark.</li></ul><br><strong>Calculation Methods:</strong> Price-weighted (DJIA), Market-cap weighted (S&P 500), Equal-weighted."},
{t:"Types of Orders",d:"20min",content:"<strong>Essential Order Types:</strong><ul><li><strong>Market Order</strong> — Buy/sell immediately. Fast but no price guarantee.</li><li><strong>Limit Order</strong> — Buy at ≤ price, sell at ≥ price. You control price, not execution.</li><li><strong>Stop-Loss</strong> — Sells automatically when price drops to stop level. Essential risk management.</li><li><strong>Stop-Limit</strong> — Stop trigger + limit price. More control but risk of no fill.</li><li><strong>Trailing Stop</strong> — Moves up with price. Locks in profits.</li><li><strong>Fill-or-Kill</strong> — Must fill entire order immediately or cancel.</li></ul><br><strong>Pro Tip:</strong> Always use stop-loss orders. The #1 beginner mistake is not having an exit plan."},
{t:"Reading a Stock Quote",d:"15min",content:"<strong>Stock Quote Anatomy:</strong><ul><li><strong>Last Price</strong> — Most recent trade</li><li><strong>Change ($ / %)</strong> — From previous close</li><li><strong>Open / High / Low</strong> — Today's range</li><li><strong>Volume</strong> — Shares traded today</li><li><strong>52-Week High/Low</strong> — Annual range</li><li><strong>P/E Ratio</strong> — Price / Earnings per share</li><li><strong>Dividend Yield</strong> — Annual dividend / Stock price</li></ul><br><strong>Reading Volume:</strong> Volume above average = strong conviction. Low volume moves are less reliable."}
],
quiz:[{q:"What does P/E ratio measure?",opts:["A company's debt level","How much investors pay per dollar of earnings","The stock's dividend payout","Revenue growth"],ans:1},{q:"A bear market is typically defined as a decline of at least:",opts:["10%","15%","20%","30%"],ans:2},{q:"Which order type guarantees your price but not execution?",opts:["Market order","Stop-loss","Limit order","Trailing stop"],ans:2}]},

{id:2,title:"Forex Trading 101",level:"beginner",icon:"💱",desc:"Understand the $6.6 trillion/day forex market and currency pairs.",duration:"2h 45min",modules:6,
lessons:[
{t:"What Is Forex?",d:"15min",content:"<strong>Forex</strong> is the global decentralized market for trading currencies — the largest financial market ($6.6 trillion daily volume).<br><br><ul><li><strong>24/5 Market</strong> — Sunday 5 PM ET to Friday 5 PM ET</li><li><strong>Decentralized</strong> — No central exchange; traded OTC</li><li><strong>Major Sessions</strong> — Asian (Tokyo), European (London), North American (New York)</li><li><strong>High Leverage</strong> — Commonly 50:1 to 100:1</li></ul><br>90% of volume is speculative."},
{t:"Currency Pairs Explained",d:"20min",content:"<strong>Currencies trade in pairs.</strong> Buying EUR/USD = buying EUR, selling USD.<br><br><strong>Categories:</strong><ul><li><strong>Majors</strong> — EUR/USD, GBP/USD, USD/JPY, USD/CHF, AUD/USD, USD/CAD, NZD/USD</li><li><strong>Crosses</strong> — No USD (EUR/GBP, EUR/JPY)</li><li><strong>Exotics</strong> — Major + emerging (USD/TRY, EUR/ZAR)</li></ul><br><strong>Reading Quotes:</strong> EUR/USD = 1.0850 means 1 EUR = 1.0850 USD. First = base, second = quote.<br><br><strong>Pip:</strong> Smallest price move. Most pairs: 0.0001. JPY pairs: 0.01."},
{t:"Leverage and Margin",d:"20min",content:"<strong>Leverage</strong> lets you control large positions with small deposits.<br><br><ul><li>Leverage 100:1 → $1,000 controls $100,000</li><li><strong>Margin</strong> — Deposit required (1-2% for majors)</li><li><strong>Margin Call</strong> — Equity below required level</li><li><strong>Stop-Out</strong> — Broker closes positions automatically</li></ul><br>⚠️ <strong>Risk:</strong> With 100:1 leverage, a 1% adverse move = 100% loss of margin. Always use stop-losses. Risk max 1-2% per trade."},
{t:"Forex Trading Sessions",d:"15min",content:"<strong>Three Major Sessions:</strong><ul><li><strong>Asian (Tokyo)</strong> — 7 PM–4 AM ET. JPY, AUD, NZD. Lower volatility.</li><li><strong>European (London)</strong> — 3 AM–12 PM ET. Highest volume. EUR, GBP, CHF.</li><li><strong>North American (NY)</strong> — 8 AM–5 PM ET. USD, CAD. High volatility at open.</li></ul><br><strong>Best Times:</strong> London-NY overlap (8 AM–12 PM ET) — Highest liquidity and volatility."},
{t:"Fundamental Analysis for Forex",d:"20min",content:"<strong>Key Indicators:</strong><ul><li><strong>Interest Rates</strong> — #1 driver. Higher rates → currency appreciates</li><li><strong>CPI / Inflation</strong> → Potential rate hikes → currency strengthens</li><li><strong>GDP Growth</strong> → Strong economy attracts investment</li><li><strong>NFP</strong> → Massive Friday volatility</li><li><strong>Trade Balance</strong> → Surplus = demand</li></ul><br><strong>Central Bank Watch:</strong> The Fed, ECB, BOJ, BOE are most influential. Forward guidance often moves markets more than actual decisions."},
{t:"Common Forex Mistakes",d:"15min",content:"<strong>Top Mistakes:</strong><ul><li><strong>Over-leveraging</strong> — Use 10:1 or less as beginner</li><li><strong>No Stop-Loss</strong> — Always set stops</li><li><strong>Trading News Without a Plan</strong> — Spikes can hit your stop first</li><li><strong>Revenge Trading</strong> — Destroys accounts</li><li><strong>Ignoring the Trend</strong> — Don't fight the dominant direction</li><li><strong>Switching Strategies Too Often</strong> — Give strategy 100+ trades</li></ul><br><strong>The 1% Rule:</strong> Never risk more than 1% of account per trade."}
],
quiz:[{q:"What is a pip in EUR/USD?",opts:["0.001","0.0001","0.01","0.1"],ans:1},{q:"Which forex session has highest volume?",opts:["Asian","North American","European","All equal"],ans:2},{q:"What is the #1 driver of currency values?",opts:["GDP","Interest rates","Trade balance","Stock market"],ans:1}]},

{id:3,title:"Candlestick Patterns Mastery",level:"beginner",icon:"🕯️",desc:"Read candlestick charts like a pro.",duration:"3h",modules:6,
lessons:[
{t:"Anatomy of a Candlestick",d:"15min",content:"<strong>Each candlestick tells a story</strong> about the battle between buyers and sellers.<br><br><ul><li><strong>Body</strong> — Open to Close. Green = bullish. Red = bearish.</li><li><strong>Upper Shadow</strong> — Highest price reached</li><li><strong>Lower Shadow</strong> — Lowest price reached</li></ul><br><strong>Body Size:</strong> Long = strong conviction. Short = indecision. No body (Doji) = equilibrium.<br><br><strong>Shadows:</strong> Long upper = sellers pushed down. Long lower = buyers rejected lows."},
{t:"Single Candlestick Patterns",d:"20min",content:"<strong>Key Patterns:</strong><ul><li><strong>Doji</strong> — Open ≈ Close. Indecision. Potential reversal after trend.</li><li><strong>Hammer</strong> — Small body at top, long lower shadow. At downtrend bottom = bullish reversal.</li><li><strong>Hanging Man</strong> — Same shape as hammer but at top = bearish reversal.</li><li><strong>Shooting Star</strong> — Small body at bottom, long upper shadow. At top = bearish.</li><li><strong>Marubozu</strong> — No shadows. Extreme buying/selling pressure.</li></ul><br><strong>Rule:</strong> Single candles are signals, not confirmations. Wait for next candle."},
{t:"Dual Candlestick Patterns",d:"20min",content:"<strong>Two-Candle Reversal Patterns:</strong><ul><li><strong>Bullish Engulfing</strong> — Red candle followed by larger green. Strong bottom reversal.</li><li><strong>Bearish Engulfing</strong> — Green then larger red. Top reversal.</li><li><strong>Tweezer Tops/Bottoms</strong> — Matching highs/lows. Rejection of price level.</li><li><strong>Harami</strong> — Large candle + smaller one inside. Trend losing momentum.</li><li><strong>Dark Cloud Cover</strong> — Bearish at tops. Piercing Line = bullish opposite.</li></ul><br><strong>Reliability:</strong> Engulfing > Piercing/Dark Cloud > Harami > Tweezer"},
{t:"Triple Candlestick Patterns",d:"20min",content:"<strong>Most Reliable Patterns:</strong><ul><li><strong>Morning Star</strong> — Large red → small body gapping down → large green. Powerful bottom reversal.</li><li><strong>Evening Star</strong> — Reverse. Top reversal. Very reliable.</li><li><strong>Three White Soldiers</strong> — 3 consecutive large green candles. Strong bullish.</li><li><strong>Three Black Crows</strong> — 3 consecutive red. Strong bearish.</li></ul><br><strong>Tip:</strong> Three-candle patterns at key S/R levels are the most reliable signals in technical analysis."},
{t:"Continuation Patterns",d:"15min",content:"<strong>Trend Continuation Candle Patterns:</strong><ul><li><strong>Rising Three Methods</strong> — Long green, 3 small red inside range, then long green. Bullish continuation.</li><li><strong>Falling Three Methods</strong> — Bearish version.</li><li><strong>Mat Hold</strong> — Similar but small candles can gap. Very bullish.</li></ul><br>Continuation patterns help you hold winning positions with confidence."},
{t:"Combining Candles with Indicators",d:"15min",content:"<strong>High-Probability Combos:</strong><ul><li><strong>Engulfing + RSI Divergence</strong> = Very strong sell signal</li><li><strong>Hammer + Support Level</strong> = High-probability bounce</li><li><strong>Doji + Bollinger Band Touch</strong> = Potential reversal</li><li><strong>Morning/Evening Star + Volume</strong> = Stronger signal</li></ul><br><strong>Golden Rule:</strong> Never trade a pattern alone. Confirm with: (1) S/R, (2) An indicator, (3) Volume."}
],
quiz:[{q:"What does a hammer signal at a downtrend bottom?",opts:["Continuation","Bearish reversal","Bullish reversal","No signal"],ans:2},{q:"Which is most reliable?",opts:["Doji","Single candle","Three-candle pattern","Spinning top"],ans:2},{q:"A bullish engulfing pattern consists of:",opts:["Two green candles","Red candle engulfed by larger green","Three red candles","Doji then green candle"],ans:1}]},

{id:4,title:"Support & Resistance Trading",level:"beginner",icon:"📏",desc:"Master the foundation of all technical analysis.",duration:"2h 15min",modules:5,
lessons:[
{t:"What Are Support & Resistance?",d:"15min",content:"<strong>Support</strong> — Price floor where buying prevents decline.<br><strong>Resistance</strong> — Price ceiling where selling prevents advance.<br><br><strong>Why They Work:</strong><ul><li><strong>Memory</strong> — Traders remember where price reversed</li><li><strong>Orders Cluster</strong> — Stop-losses and limits accumulate</li><li><strong>Self-Fulfilling</strong> — Millions watch the same levels</li></ul><br><strong>Key Insight:</strong> When support breaks, it becomes resistance. When resistance breaks, it becomes support."},
{t:"Identifying Key Levels",d:"20min",content:"<strong>How to Find Significant Levels:</strong><ul><li><strong>Multiple Touches</strong> — 3+ touches = significant</li><li><strong>Volume at the Level</strong> — High volume confirms importance</li><li><strong>Time</strong> — Weeks/months > intraday levels</li><li><strong>Round Numbers</strong> — $100, $150 etc. = psychological S/R</li><li><strong>Prior Swing Highs/Lows</strong></li></ul><br><strong>Methods:</strong> Manual chart analysis (most reliable), Pivot points, Fibonacci, Volume Profile."},
{t:"Trading Bounces at S/R",d:"20min",content:"<strong>Buy at Support, Sell at Resistance</strong><br><br><strong>Entry Rules:</strong><ul><li>Wait for price to reach the level</li><li>Look for reversal candlestick (hammer, engulfing)</li><li>Enter on confirmation (candle close)</li><li>Stop-loss just beyond the level</li></ul><br><strong>Example:</strong> Stock at $95, support at $92. Price touches $92, forms hammer. Entry: $92.50. Stop: $91.50. Target: $98. Risk $1 → Reward $5.50 = 5.5:1 R:R."},
{t:"Breakout Trading",d:"20min",content:"<strong>When S/R Breaks:</strong><ul><li><strong>True Breakout</strong> — Closes beyond level with strong volume</li><li><strong>False Breakout</strong> — Pokes beyond then reverses (traps early entrants)</li></ul><br><strong>How to Trade:</strong><ul><li>Wait for candle CLOSE beyond the level</li><li>Volume should be 1.5x+ average</li><li>Enter after close, stop just inside broken level</li><li>Target = distance from S/R level projected</li></ul><br><strong>False Breakout Strategy:</strong> If price breaks below support but can't hold, enter LONG — often the strongest signal."},
{t:"Dynamic S/R: Moving Averages & Trendlines",d:"15min",content:"<strong>Moving Average S/R:</strong><ul><li><strong>20 EMA</strong> — Short-term dynamic support</li><li><strong>50 SMA</strong> — Institutional traders watch this</li><li><strong>200 SMA</strong> — Most important. Above = bull market; below = bear.</li></ul><br><strong>Trendline S/R:</strong> Connect 2+ swing lows (uptrend) or highs (downtrend). 3+ touches = valid. Break = trend change."}
],
quiz:[{q:"When support breaks, it becomes:",opts:["Nothing","Resistance","Stronger support","A trendline"],ans:1},{q:"Which MA is the most important long-term level?",opts:["20 EMA","50 SMA","100 SMA","200 SMA"],ans:3},{q:"True breakouts should be confirmed by:",opts:["A doji candle","Low volume","High volume and candle close beyond level","A gap"],ans:2}]},

{id:5,title:"Moving Averages Deep Dive",level:"beginner",icon:"📊",desc:"SMA, EMA, and how to use them for trend identification.",duration:"2h",modules:5,
lessons:[
{t:"Simple vs Exponential Moving Average",d:"15min",content:"<strong>SMA</strong> — Average of closing prices over N periods. Equal weight.<br><strong>EMA</strong> — More weight to recent prices. Faster response.<br><br><strong>Which to Use?</strong> SMA for trend identification (smoother). EMA for entry/exit signals (faster). Most traders use both."},
{t:"Golden Cross & Death Cross",d:"15min",content:"<strong>Golden Cross</strong> — 50 SMA crosses ABOVE 200 SMA. Bullish. Average 12-month return ≈ +14%.<br><strong>Death Cross</strong> — 50 SMA crosses BELOW 200 SMA. Bearish. Average 12-month return ≈ -3%.<br><br>These are trend confirmation signals, not entry signals. Use them to determine market direction."},
{t:"MA Crossover Strategies",d:"20min",content:"<strong>Popular Systems:</strong><ul><li><strong>9/21 EMA</strong> — Fast swing trading</li><li><strong>20/50 SMA</strong> — Medium-term position trading</li><li><strong>50/200 SMA</strong> — Long-term trend</li></ul><br><strong>Improving Crossovers:</strong> Add 200 SMA filter, wait for retest, use ADX for trend strength, combine with RSI."},
{t:"Price & MA Relationships",d:"15min",content:"<strong>Key Relationships:</strong><ul><li><strong>Above Rising MA</strong> — Strong uptrend. MA = dynamic support.</li><li><strong>Below Falling MA</strong> — Downtrend. MA = dynamic resistance.</li><li><strong>MA Flatten</strong> — Trend weakening.</li></ul><br><strong>20 EMA Rule:</strong> In strong trends, price stays on one side of 20 EMA. Frequent crossing = ranging market."},
{t:"Multiple MA Ribbon Strategy",d:"15min",content:"<strong>MA Ribbons</strong> — Plot 6-8 MAs (10-60 period).<br><br><strong>Reading:</strong> Expansion = strong trend. Contraction = trend ending. Fanning up = bullish strengthening. Fanning down = bearish.<br><br>Enter when ribbon fans out after contraction. Exit when contracting."}
],
quiz:[{q:"Which MA reacts faster?",opts:["SMA","EMA","Both same","Depends on timeframe"],ans:1},{q:"Golden Cross occurs when:",opts:["9 EMA crosses 21 EMA","50 SMA crosses above 200 SMA","Price crosses 200 SMA","Volume spikes"],ans:1},{q:"MA ribbon contraction suggests:",opts:["Strong trend","Trend ending or consolidation","Breakout imminent","Volume increase"],ans:1}]},

{id:6,title:"RSI & MACD Indicators",level:"intermediate",icon:"📉",desc:"Two powerful indicators — beyond basic overbought/oversold.",duration:"2h 30min",modules:5,
lessons:[
{t:"RSI Deep Dive",d:"20min",content:"<strong>RSI</strong> measures speed and magnitude of price changes (0-100 scale). Default: 14 periods.<br><br><strong>Traditional:</strong> Above 70 = Overbought. Below 30 = Oversold.<br><br><strong>Advanced:</strong><ul><li><strong>Bull/Bear Ranges</strong> — Uptrend: RSI stays 40-80. Downtrend: 20-60.</li><li><strong>RSI Divergence</strong> — Price & RSI disagree. Strongest RSI signal.</li><li><strong>Failure Swings</strong> — RSI drops below 30, rises, pulls back above 30 = bullish.</li></ul>"},
{t:"RSI Divergence Trading",d:"20min",content:"<strong>Divergence Types:</strong><ul><li><strong>Bullish</strong> — Price lower low, RSI higher low. Selling fading. Look for longs.</li><li><strong>Bearish</strong> — Price higher high, RSI lower high. Buying weakening. Look for shorts.</li><li><strong>Hidden Bullish</strong> — Price higher low, RSI lower low. Trend continuation.</li><li><strong>Hidden Bearish</strong> — Price lower high, RSI higher high. Continuation down.</li></ul><br>Only trade divergences in direction of higher timeframe trend. Combine with S/R."},
{t:"MACD Explained",d:"20min",content:"<strong>Components:</strong><ul><li><strong>MACD Line</strong> — 12 EMA minus 26 EMA</li><li><strong>Signal Line</strong> — 9 EMA of MACD line</li><li><strong>Histogram</strong> — MACD minus Signal. Shows momentum.</li></ul><br><strong>Key Signals:</strong> MACD crosses above Signal = buy. Below = sell. Zero line cross = momentum shift. Best on daily chart."},
{t:"MACD Trading Strategies",d:"20min",content:"<strong>3 Proven Strategies:</strong><br><br>1. <strong>Trend Following (Crossover + 200 SMA):</strong> Only buy signals above 200 SMA. Filters ~40% false signals.<br><br>2. <strong>Momentum Shift (Histogram):</strong> When histogram bars shrink 3+ periods after expansion, enter opposite direction.<br><br>3. <strong>Zero-Line Rejection:</strong> MACD approaches zero but bounces. Confirms trend strength."},
{t:"Combining RSI + MACD",d:"15min",content:"<strong>When Both Agree = High Confidence:</strong><br><br>Bullish: RSI divergence/bounce + MACD bullish crossover + Price at support → High-probability long.<br><br>Bearish: RSI divergence/rejecting + MACD bearish crossover + Price at resistance → High-probability short.<br><br><strong>When They Disagree:</strong> DON'T trade. Wait for alignment."}
],
quiz:[{q:"What is the strongest RSI signal?",opts:["Overbought","Oversold","RSI divergence","RSI at 50"],ans:2},{q:"MACD histogram shows:",opts:["Price volume","Momentum","Moving averages","Support levels"],ans:1},{q:"When RSI and MACD disagree:",opts:["Follow RSI","Follow MACD","Trade the stronger","Don't trade, wait for alignment"],ans:3}]},

{id:7,title:"Risk Management Essentials",level:"beginner",icon:"🛡️",desc:"The most important skill — protecting your capital.",duration:"2h",modules:5,
lessons:[
{t:"Why Risk Management Matters Most",d:"15min",content:"<strong>90% of traders lose money. The difference? Risk management.</strong><br><br><strong>The Math of Losses:</strong><ul><li>Lose 10% → Need 11.1% to recover</li><li>Lose 25% → Need 33.3%</li><li>Lose 50% → Need 100%</li><li>Lose 90% → Need 900%</li></ul><br>One bad trade can wipe out months of gains. Preserving capital > making profits."},
{t:"Position Sizing",d:"20min",content:"<strong>Formula:</strong> Position Size = (Account × Risk%) / (Entry - Stop-Loss)<br><br><strong>Example:</strong> $50K account, 1% risk = $500. Entry $100, Stop $97 ($3 risk). Position = $500/$3 = 166 shares.<br><br>Without sizing: might buy 500 shares and risk $1,500 (3%). With sizing: risk exactly $500 (1%) regardless of setup."},
{t:"Stop-Loss Strategies",d:"20min",content:"<strong>Types:</strong><ul><li><strong>Fixed %</strong> — Simple but ignores market structure</li><li><strong>Technical</strong> — Below support (long) or above resistance (short). Best.</li><li><strong>ATR-based</strong> — 2× ATR below entry. Adjusts to volatility.</li><li><strong>Trailing Stop</strong> — Moves up with price. Locks profits.</li><li><strong>Time Stop</strong> — Exit if no move within X days.</li></ul><br><strong>Rules:</strong> NEVER widen your stop. You CAN tighten it. Always set before entering."},
{t:"Risk-Reward Ratio",d:"15min",content:"<strong>Minimum R:R by Strategy:</strong><ul><li>Scalping: 1:1 (needs 60%+ win rate)</li><li>Day Trading: 1:1.5</li><li>Swing Trading: 1:2 (profitable with 40% win rate)</li><li>Position Trading: 1:3+</li></ul><br><strong>1:2 R:R:</strong> Win 40% = still profitable. Win 50% = strong edge. If you can't find 1:2, don't trade."},
{t:"Portfolio Risk Management",d:"15min",content:"<strong>Beyond Single Trades:</strong><ul><li>Max risk per trade: 1-2%</li><li>Max open risk: ≤ 5-6%</li><li>Max sector: 20-25%</li><li>Daily loss limit: 3% → stop trading</li><li>Weekly loss limit: 6% → reevaluate</li></ul><br><strong>The 3% Daily Rule:</strong> Hit -3%? Close everything and walk away. Revenge trading destroys accounts."}
],
quiz:[{q:"Lose 50%, how much gain to recover?",opts:["50%","75%","100%","150%"],ans:2},{q:"Minimum R:R for swing trading?",opts:["1:1","1:1.5","1:2","1:3"],ans:2},{q:"Max recommended risk per trade:",opts:["5%","3%","1-2%","0.5%"],ans:2}]},

{id:8,title:"Trading Psychology",level:"intermediate",icon:"🧠",desc:"Master your emotions — the hidden edge separating winners from losers.",duration:"2h 15min",modules:5,
lessons:[
{t:"Fear & Greed in Trading",d:"15min",content:"<strong>Fear</strong> — Panic selling at bottoms, prevents taking valid setups, premature profit-taking.<br><strong>Greed</strong> — Chasing rallies, holding losers, over-leveraging, ignoring stops.<br><br>Most traders buy at tops (greed), sell at bottoms (fear). <strong>Solution:</strong> Have a written plan and follow it mechanically."},
{t:"Cognitive Biases That Kill Trades",d:"20min",content:"<strong>Top Biases:</strong><ul><li><strong>Confirmation Bias</strong> — Only seeing what supports your position</li><li><strong>Loss Aversion</strong> — Losses hurt 2× more. Leads to holding losers.</li><li><strong>Recency Bias</strong> — Overweighting recent events</li><li><strong>Anchoring</strong> — Fixating on a specific price ('I'll sell when it gets back to entry')</li><li><strong>Overconfidence</strong> — Increasing size after winning streak</li></ul>"},
{t:"Building a Trading Journal",d:"20min",content:"<strong>#1 Improvement Tool.</strong> Record: date, instrument, entry/stop/target, reason, chart screenshot, emotional state (1-10), outcome, lessons.<br><br><strong>Weekly Review:</strong> Win rate, avg R:R, best/worst trades, rule violations, patterns in mistakes, adjustments."},
{t:"Developing Discipline",d:"15min",content:"<strong>Discipline = Doing What You Should, Not What You Feel.</strong><br><br>Start with demo 3 months → micro lots 3 months → increase size only after consistent profitability. Take breaks after 3 consecutive losses. No trading when tired, angry, or distracted."},
{t:"The Mindset of Successful Traders",d:"15min",content:"<strong>What Separates the 10%:</strong><ul><li><strong>Process over outcome</strong> — A losing trade following your plan is a good trade</li><li><strong>Accept losses as costs</strong> — Like rent for a business</li><li><strong>Patience</strong> — Best traders sit on hands 80% of the time</li><li><strong>Humility</strong> — The market is always right</li></ul><br><strong>Paradox:</strong> To make money, stop focusing on making money. Focus on executing correctly."}
],
quiz:[{q:"Which bias causes holding losers too long?",opts:["Confirmation","Loss aversion","Recency","Overconfidence"],ans:1},{q:"After 3 consecutive losses:",opts:["Increase size","Trade more","Take a break","Change strategy"],ans:2},{q:"A losing trade following your plan is:",opts:["A bad trade","A good trade","A waste","Should be avoided"],ans:1}]},

{id:9,title:"Fibonacci Trading",level:"intermediate",icon:"🌀",desc:"Use Fibonacci retracements and extensions for precise entries and targets.",duration:"2h",modules:5,
lessons:[
{t:"Fibonacci in Markets",d:"15min",content:"<strong>Key Ratios:</strong> 23.6% (minor), 38.2% (moderate), 50% (widely watched), 61.8% (Golden Ratio — most important), 78.6% (deep).<br><br>Works due to self-fulfilling prophecy — millions of traders use the same levels. Institutional algorithms use Fib levels."},
{t:"Drawing Fibonacci Retracements",d:"20min",content:"<strong>Uptrend:</strong> Draw from swing LOW to HIGH. 38.2%, 50%, 61.8% are buy zones.<br><strong>Downtrend:</strong> Draw from HIGH to LOW. Levels are sell zones.<br><br><strong>Mistakes:</strong> Wrong swing points, too small timeframes (use 1H+), ignoring the trend."},
{t:"Trading Fibonacci Bounces",d:"20min",content:"<strong>Strategy: Buy at Fib support in uptrends.</strong> Wait for pullback to 38.2% or 50%, look for reversal candle, enter with stop below 61.8%.<br><br><strong>The 61.8% Rule:</strong> Beyond 61.8% = trend likely broken. Use as invalidation level.<br><br><strong>Confluence:</strong> Fib + S/R + MA + RSI divergence = highest probability."},
{t:"Fibonacci Extensions for Targets",d:"15min",content:"<strong>Key Extensions:</strong> 127.2% (minimum), 161.8% (standard — most commonly hit), 200% (extended), 261.8% (strong trends).<br><br>Set take-profit at 161.8%. Use 127.2% for conservative targets."},
{t:"Multiple Timeframe Fibonacci",d:"15min",content:"<strong>MTF Fibonacci:</strong> Draw Fib on daily + 4H + 1H charts. Where levels from different timeframes CLUSTER = high-probability zones.<br><br>Fib clusters work best with volume confirmation."}
],
quiz:[{q:"Which is the Golden Ratio?",opts:["38.2%","50%","61.8%","78.6%"],ans:2},{q:"Beyond 61.8% retracement suggests:",opts:["Strong buy","Trend may be broken","Add to position","Fib doesn't apply"],ans:1},{q:"Most commonly hit extension target:",opts:["127.2%","161.8%","200%","261.8%"],ans:1}]},

{id:10,title:"Bollinger Bands Strategy",level:"intermediate",icon:"📈",desc:"Trade with volatility — squeeze, expansion, and mean reversion.",duration:"2h",modules:5,
lessons:[
{t:"Understanding Bollinger Bands",d:"15min",content:"<strong>Three lines:</strong> Middle (20 SMA), Upper (20 SMA + 2×SD), Lower (20 SMA - 2×SD).<br><br>Measures volatility. Band width expands when volatile, contracts when calm. Price stays within bands ~95% of the time."},
{t:"The Bollinger Squeeze",d:"20min",content:"<strong>When bands contract to 6-month narrowest</strong>, a significant move is coming.<br><br>Don't predict direction — wait for breakout with volume. Stop at opposite band or middle. Combine with RSI for direction clues."},
{t:"Mean Reversion with BB",d:"20min",content:"<strong>Buy at Lower Band, Sell at Upper Band — only in ranging markets.</strong><br><br>Ranging identification: Flat bands, price crosses middle frequently, ADX < 25.<br><br>⚠️ In trends, price can 'ride the bands.' Don't short just because it touched upper band in an uptrend."},
{t:"BB Width & %B Indicator",d:"15min",content:"<strong>Band Width</strong> = (Upper - Lower) / Middle × 100. Identifies low-volatility periods.<br><br><strong>%B</strong> = (Price - Lower) / (Upper - Lower). 0 = lower band, 0.5 = middle, 1.0 = upper band.<br><br>Buy when %B drops below 0 then returns above. Sell when %B rises above 1 then returns below."},
{t:"Combining BB with Other Indicators",d:"15min",content:"<strong>High-Probability Combos:</strong><ul><li>BB + RSI — Upper band + RSI divergence = strong sell</li><li>BB + MACD — Squeeze + MACD histogram turning = early direction</li><li>BB + Volume — Upper band + declining volume = reversal</li><li>BB + S/R — Band at key level = very strong zone</li></ul><br>When all signals align: 70%+ probability trade."}
],
quiz:[{q:"Price stays within BB approximately:",opts:["68%","80%","95%","99%"],ans:2},{q:"Bollinger Squeeze signals:",opts:["Reversal coming","Volatility decreasing permanently","Significant move coming","Market trending"],ans:2},{q:"Short just because price touched upper band in uptrend?",opts:["Yes, overbought","No, price can ride the bands","Only with confirmation","Depends on volume"],ans:1}]},

{id:11,title:"Chart Patterns Complete Guide",level:"intermediate",icon:"📊",desc:"Head & Shoulders, Triangles, Wedges — read what the market tells you.",duration:"3h",modules:6,
lessons:[
{t:"Reversal Patterns Overview",d:"15min",content:"<strong>Most Reliable:</strong> Head & Shoulders, Double Top/Bottom, Triple Top/Bottom, Rising/Falling Wedge.<br><br><strong>Rules:</strong> Must have prior trend. Longer formation = larger move. Volume decreases during formation, increases on breakout. Wait for neckline break. Target = pattern height from breakout."},
{t:"Head & Shoulders Pattern",d:"20min",content:"<strong>Structure:</strong> Left Shoulder → Head (higher) → Right Shoulder (≈ left). Neckline connects troughs.<br><br>Entry: Short on neckline break. Stop: Above right shoulder. Target: Head-to-neckline distance projected down.<br><br><strong>Inverse H&S:</strong> Same pattern upside-down. Bullish. Entry on neckline break upward."},
{t:"Double Top & Double Bottom",d:"20min",content:"<strong>Double Top (M-shape):</strong> Two peaks at same level. Confirmed on break below valley. Target = peak-to-valley projected down.<br><br><strong>Double Bottom (W-shape):</strong> Two troughs at same level. Confirmed on break above peak. Target = valley-to-peak projected up.<br><br>Failure rate: ~15-20%. Always wait for confirmation."},
{t:"Triangle Patterns",d:"20min",content:"<strong>Symmetric:</strong> Converging lines. 65% break in trend direction.<br><strong>Ascending (Bullish):</strong> Flat top + rising bottom. Breaks up 75%.<br><strong>Descending (Bearish):</strong> Flat bottom + falling top. Breaks down 75%.<br><br>Best breakouts in middle 1/3 of triangle. Final 1/3 less reliable."},
{t:"Wedge & Flag Patterns",d:"20min",content:"<strong>Rising Wedge = Bearish.</strong> Falling Wedge = Bullish.<br><br><strong>Bull/Bear Flags:</strong> Strong move (flagpole) + shallow counter-trend channel. Flag retrace ≤ 50% of pole. Target = flagpole from breakout. One of the most reliable continuation patterns."},
{t:"Measuring Price Targets",d:"15min",content:"<strong>Targets:</strong> H&S: Head-to-neckline projected. Double Top/Bottom: Peak/trough to neckline projected. Triangles: Base height projected. Flags: Flagpole length projected.<br><br>Full target reached ~60%. Half target ~80%. Consider partial profits at 50% target."}
],
quiz:[{q:"H&S stop-loss placement:",opts:["Below neckline","Above right shoulder","At the head","At left shoulder"],ans:1},{q:"Ascending triangle breaks upward:",opts:["50%","65%","75%","90%"],ans:2},{q:"Rising wedge is typically:",opts:["Bullish","Bearish","Neutral","Continuation"],ans:1}]},

{id:12,title:"Volume Analysis",level:"intermediate",icon:"📊",desc:"Volume precedes price — read what the smart money is doing.",duration:"2h",modules:5,
lessons:[
{t:"Why Volume Matters",d:"15min",content:"<strong>Volume = Fuel.</strong> Price up + Volume up = healthy. Price up + Volume down = weak rally. Price down + Volume up = strong selling. Price down + Volume down = potential bottom.<br><br>A car can coast without fuel but can't sustain it."},
{t:"Volume Patterns & Signals",d:"20min",content:"<strong>Key Patterns:</strong><ul><li><strong>Volume Climax</strong> — Extremely high volume after extended move. Often marks the end.</li><li><strong>Volume Dry-Up</strong> — Declining volume during consolidation. Precedes breakout.</li><li><strong>Confirmation</strong> — Breakout on high volume = real. Low volume = suspect.</li></ul>"},
{t:"On-Balance Volume (OBV)",d:"20min",content:"<strong>OBV adds volume on up days, subtracts on down days.</strong><br><br>OBV rising + Price flat/falling = Accumulation (smart money buying). OBV falling + Price rising = Distribution (smart money selling).<br><br>OBV leads price by 1-3 days on average."},
{t:"Volume at Price (VAP)",d:"15min",content:"<strong>Shows volume at each price level.</strong> HVNs (high volume) = support/resistance. LVNs (low volume) = price moves through quickly. POC = fair value.<br><br>Enter near HVNs. Expect fast moves through LVNs."},
{t:"Institutional Footprints",d:"15min",content:"<strong>Spot Smart Money:</strong> High volume with no price change = accumulation/distribution. Sudden volume spike after quiet = smart money entering. Volume at open/close = institutional activity.<br><br>Volume without price movement = smartest money positioning for large move."}
],
quiz:[{q:"Price up + volume down suggests:",opts:["Strong bullish","Healthy trend","Weak rally","Reversal imminent"],ans:2},{q:"OBV leads price by:",opts:["1 week","1-3 days","1 hour","1 month"],ans:1},{q:"Price moves quickly through:",opts:["High Volume Nodes","Low Volume Nodes","POC","Support"],ans:1}]},

{id:13,title:"Swing Trading Strategies",level:"intermediate",icon:"🔄",desc:"Capture multi-day moves with proven setups.",duration:"2h 30min",modules:5,
lessons:[
{t:"What Is Swing Trading?",d:"15min",content:"<strong>2 days to 2 weeks holding period.</strong> Between day trading and position trading.<br><br>Don't need to watch screens all day. Lower stress. Can do with full-time job. Best timeframes: Daily (primary) + 4H (secondary)."},
{t:"The Pullback Strategy",d:"20min",content:"<strong>Buy the dip in uptrend — highest-probability swing trade.</strong><br><br>Setup: Strong uptrend (50 SMA > 200 SMA) → Pullback to 20 EMA or 50 SMA → Bullish reversal candle → Enter on close. Stop below swing low. Target: previous high or Fib extension.<br><br>Win rate: 50-60% with 1:2+ R:R."},
{t:"Breakout Pullback Strategy",d:"20min",content:"<strong>Trade the retest after breakout — higher win rate than trading breakout itself.</strong><br><br>Wait for price to break resistance → pullback to broken resistance (now support) → bullish signal → enter. Confirms level flip, better R:R, filters false breakouts. Win rate: 55-65%."},
{t:"Flag & Pennant Trading",d:"20min",content:"<strong>Most reliable swing setup.</strong> Strong impulse (flagpole) + slight counter-trend channel (flag). Flag retrace ≤ 50% of pole. Enter on channel break. Target = flagpole length from breakout."},
{t:"Swing Trade Management",d:"15min",content:"<strong>Management Rules:</strong> Move stop to breakeven after 1R profit. Trail using 20 EMA. Partial exits: 50% at 1:2 R:R. Time exit: If no move in 5 days, consider exiting.<br><br><strong>Weekly Routine:</strong> Friday scan → Monday alerts → Week management → Friday review."}
],
quiz:[{q:"Typical swing trade holding period:",opts:["Minutes","2 days to 2 weeks","1-6 months","1 year+"],ans:1},{q:"Why breakout pullback > breakout trade?",opts:["More exciting","Better R:R + filters false breakouts","Less capital","Always wins"],ans:1},{q:"Bull flag retrace max:",opts:["20%","38-50%","75%","100%"],ans:1}]},

{id:14,title:"Day Trading Fundamentals",level:"advanced",icon:"⚡",desc:"Fast-paced trading for experienced traders.",duration:"2h 30min",modules:5,
lessons:[
{t:"Is Day Trading Right for You?",d:"15min",content:"<strong>Reality:</strong> 90%+ lose money. Requires 2+ hours daily. $25K+ for US PDT rule. Extreme discipline. Months of practice.<br><br>Start with paper trading for 3+ months. If not profitable on paper, won't be with real money."},
{t:"The Opening Range Breakout",d:"20min",content:"<strong>Mark high/low of first 15-30 min</strong>. Break above = long. Break below = short. Stop: middle of range. Target: 1-2× range height.<br><br>Only trade with daily trend. Volume above average on breakout. Best 9:30-10:30 AM ET. No breakout by 10:30 = void."},
{t:"VWAP Trading Strategy",d:"20min",content:"<strong>VWAP = most important intraday indicator.</strong> Price above VWAP = bullish intraday. Below = bearish. VWAP acts as dynamic S/R.<br><br>VWAP bounce: In uptrend day, buy pullback to VWAP with reversal candle. Stop below VWAP. VWAP resets daily."},
{t:"Scalping Techniques",d:"20min",content:"<strong>Seconds to minutes. Small profits. Need 65%+ win rate.</strong><br><br>5-min scalp: 9/21 EMA crossover + volume spike. Target 10 pips. Stop 5 pips (1:2 R:R). Max 10 trades/day.<br><br>⚠️ Highest failure rate. Commissions eat small profits. Most disciplined traders only."},
{t:"Day Trading Risk Management",d:"15min",content:"<strong>Rules:</strong> Max 3% daily loss. Max 6% weekly. Single trade: 0.5-1%. Max 5 open positions. No averaging down. Avoid holding through major news.<br><br><strong>+2/-2 Rule:</strong> Make 2× daily target → stop. Lose 2% in one trade → stop for day."}
],
quiz:[{q:"PDT minimum account:",opts:["$10K","$15K","$25K","$50K"],ans:2},{q:"VWAP resets:",opts:["Weekly","Monthly","Daily","Never"],ans:2},{q:"Add to a losing day trade?",opts:["Yes, if you believe","No, never","Only small size","Only near support"],ans:1}]},

{id:15,title:"Options Trading Basics",level:"advanced",icon:"🎯",desc:"Calls, puts, and basic strategies.",duration:"3h",modules:6,
lessons:[
{t:"What Are Options?",d:"15min",content:"<strong>Options = RIGHT (not obligation) to buy/sell at specified price before specified date.</strong><br><br>Call = Right to BUY. Put = Right to SELL. 1 contract = 100 shares. Premium = price you pay. Strike = price you can buy/sell at. Expiration = when it expires."},
{t:"Intrinsic & Extrinsic Value",d:"20min",content:"<strong>Premium = Intrinsic + Extrinsic (Time Value).</strong><br><br>Intrinsic: Call = Stock - Strike. Put = Strike - Stock. If 0 = out of the money.<br><br>Extrinsic decreases over time (theta decay). Affected by volatility (vega).<br><br>ITM = has intrinsic. ATM = strike = stock. OTM = no intrinsic."},
{t:"The Greeks",d:"20min",content:"<strong>Delta (Δ):</strong> Option price change per $1 stock move. ATM ≈ 0.50.<br><strong>Gamma (Γ):</strong> Rate of delta change. Highest ATM near expiration.<br><strong>Theta (Θ):</strong> Time decay per day. Accelerates near expiration.<br><strong>Vega (ν):</strong> Sensitivity to 1% IV change."},
{t:"Covered Calls & Protective Puts",d:"20min",content:"<strong>Covered Call:</strong> Own 100 shares + sell 1 call. Collect premium. Limited upside. Best for slightly bullish/neutral.<br><br><strong>Protective Put:</strong> Own 100 shares + buy 1 put. Insurance against big drop. Like home insurance."},
{t:"Credit Spreads",d:"20min",content:"<strong>Bull Put Spread:</strong> Sell higher put, buy lower put. Collect credit. Profit if stock stays above short put. Win rate 60-70%.<br><br><strong>Bear Call Spread:</strong> Sell lower call, buy higher call. Same risk profile.<br><br>Great for beginners: Defined risk, profit even if slightly wrong, time decay works for you."},
{t:"Options Risk Management",d:"15min",content:"<strong>Rules:</strong> Max 2-5% per trade. Options can go to zero. Avoid OTM near expiration (theta destroys them). Always have exit plan. Don't hold through earnings (IV crush).<br><br><strong>50% Rule:</strong> If option goes 50% in your favor, take partial profits."}
],
quiz:[{q:"Call option gives right to:",opts:["Sell at strike","Buy at strike","Sell at market","Buy at market"],ans:1},{q:"Which Greek measures time decay?",opts:["Delta","Gamma","Theta","Vega"],ans:2},{q:"In bull put spread, you:",opts:["Buy higher put, sell lower","Sell higher put, buy lower","Buy two puts","Sell two puts"],ans:1}]},

{id:16,title:"Crypto Trading",level:"intermediate",icon:"₿",desc:"Navigate the 24/7 crypto market.",duration:"2h 30min",modules:5,
lessons:[
{t:"How Crypto Markets Differ",d:"15min",content:"<strong>Key Differences:</strong> 24/7 trading. Extreme volatility (10-20% daily). No circuit breakers. Less regulation. Lower liquidity for altcoins.<br><br>Bitcoin dominance ≈ 50%. Halving cycle (~4 years) historically drives bull markets."},
{t:"Bitcoin & Ethereum Analysis",d:"20min",content:"<strong>BTC:</strong> Digital gold. 21M cap. Institutional adoption growing (ETFs). Key levels: ATH, 200-week MA, realized price.<br><br><strong>ETH:</strong> Smart contracts platform. DeFi/NFTs built on it. Proof of Stake (3-5% APY). ETH/BTC ratio = alt season indicator."},
{t:"Altcoin Trading",d:"20min",content:"<strong>Categories:</strong> Large caps (Top 20, lower risk). Mid caps (20-100, balanced). Small/micro (100+, 10-100x potential but 95%+ go to zero).<br><br>Alt season: BTC dominance falling, ETH/BTC rising. Never > 5% in single altcoin."},
{t:"DeFi & Yield Strategies",d:"15min",content:"<strong>Opportunities:</strong> Staking (3-20% APY), Liquidity Providing (trading fees + impermanent loss risk), Lending (Aave, Compound), Yield Farming.<br><br><strong>Risks:</strong> Smart contract bugs, impermanent loss, rug pulls, regulatory risk."},
{t:"Crypto Risk Management",d:"15min",content:"<strong>Rules:</strong> Max 5% single crypto, 15% total crypto. Cold storage (hardware wallet). 30%+ stablecoins in uncertain times. DCA strategy. Take profits at 3x (sell 50%). Never use leverage in crypto."}
],
quiz:[{q:"Crypto markets trade:",opts:["9:30-4:00 ET","24/7","Weekdays only","Asian hours only"],ans:1},{q:"Falling BTC dominance often signals:",opts:["Bear market","Alt season","Crash","BTC rally"],ans:1},{q:"Max single altcoin allocation:",opts:["50%","25%","10%","5%"],ans:3}]},

{id:17,title:"Fundamental Analysis",level:"intermediate",icon:"📋",desc:"Read financial statements like an investor.",duration:"2h 30min",modules:5,
lessons:[
{t:"Reading Financial Statements",d:"20min",content:"<strong>Income Statement:</strong> Revenue → Gross Profit → Operating Income → Net Income. Key margins: Gross, Operating, Net.<br><br><strong>Balance Sheet:</strong> Assets = Liabilities + Equity. Current Ratio > 1.5. Debt-to-Equity < 2.0.<br><br><strong>Cash Flow:</strong> Operating CF (most important), Investing CF, Financing CF."},
{t:"Key Valuation Ratios",d:"20min",content:"<strong>P/E</strong> — Price/EPS. Compare within industry. <strong>P/B</strong> — Below 1 = cheap. <strong>P/S</strong> — For unprofitable companies. <strong>EV/EBITDA</strong> — Better than P/E for different debt levels. <strong>PEG</strong> — Below 1 = undervalued. <strong>Dividend Yield</strong> — 2-4% healthy.<br><br>No single ratio tells the whole story. Use 3-4 together."},
{t:"Earnings Reports",d:"20min",content:"<strong>Top 5 Things:</strong> Revenue vs expectations. EPS vs consensus. Guidance (often moves stock more). Margins expanding/contracting. Industry-specific metrics.<br><br>Don't buy immediately after earnings. Wait for gap fill or pullback. Look for overreactions."},
{t:"Economic Moats",d:"15min",content:"<strong>Buffett's #1 Criterion.</strong> Types: Network Effect, Switching Costs, Cost Advantage, Intangible Assets, Efficient Scale.<br><br>Identify by: ROE > 15%, stable margins, pricing power, low customer churn."},
{t:"Top-Down Analysis",d:"15min",content:"<strong>4 Steps:</strong> (1) Macro: Economic cycle, interest rates, sector rotation. (2) Industry: Growth rate, competition, regulation. (3) Company: Financials, moats, management. (4) Technical: Trend, S/R, catalysts."}
],
quiz:[{q:"Which shows where cash came from?",opts:["Income Statement","Balance Sheet","Cash Flow Statement","Shareholder Equity"],ans:2},{q:"PEG below 1 suggests:",opts:["Overvalued","Fairly valued","Undervalued","High growth"],ans:2},{q:"What often moves stock more than past earnings?",opts:["Revenue","EPS","Guidance","Dividends"],ans:2}]},

{id:18,title:"ETF Investing Strategy",level:"beginner",icon:"📦",desc:"Build wealth with ETFs — the simplest path to diversification.",duration:"2h",modules:5,
lessons:[
{t:"What Are ETFs?",d:"15min",content:"<strong>ETF</strong> = basket of securities trading like a single stock. Instant diversification. Low fees (0.03-0.20%). Trade anytime. Tax efficient.<br><br>Core ETFs (70-80%) + Satellite individual stocks (20-30%) = balanced approach."},
{t:"Core ETF Portfolio",d:"20min",content:"<strong>3-Fund Boglehead:</strong> VTI (US stocks, 40%) + VXUS (International, 30%) + BND (Bonds, 30%).<br><br>Stock allocation ≈ 110 - Age. 80/20 portfolio: ~8-9% avg. 60/40: ~7%. Worst year (80/20): -35% (2008)."},
{t:"Sector & Thematic ETFs",d:"15min",content:"<strong>Sector:</strong> XLK (Tech), XLF (Financials), XLV (Healthcare), XLE (Energy). For overweighting sectors you're bullish on.<br><br><strong>Thematic:</strong> ARKK (Innovation), BOTZ (Robotics), ICLN (Clean Energy). Very concentrated, high volatility. Max 20-30% of portfolio."},
{t:"Dividend ETFs for Income",d:"15min",content:"<strong>Popular:</strong> VYM (3.0% yield), SCHD (3.5%, quality focus), VIG (1.8%, growing dividends), HDV (3.6%).<br><br>Young investors: Dividend growth (VIG). Retirees: High yield (SCHD/VYM)."},
{t:"Dollar-Cost Averaging",d:"15min",content:"<strong>DCA:</strong> Fixed amount at regular intervals, regardless of market. Buy more when low, less when high.<br><br>Lump sum beats DCA 67% of the time, but DCA reduces regret. Best: DCA for regular income, lump sum for windfalls."}
],
quiz:[{q:"Typical ETF expense ratio:",opts:["1-2%","0.03-0.20%","3-5%","0.5-1%"],ans:1},{q:"3-fund portfolio includes:",opts:["Tech/healthcare/financials","US/international/bonds","Large/mid/small cap","Growth/value/dividend"],ans:1},{q:"DCA means:",opts:["All at once","Only when down","Fixed amount at regular intervals","Only dividend stocks"],ans:2}]},

{id:19,title:"Commodities Trading",level:"intermediate",icon:"🛢️",desc:"Gold, oil, and more — trading raw materials.",duration:"2h",modules:5,
lessons:[
{t:"Commodity Market Basics",d:"15min",content:"<strong>Categories:</strong> Energy (oil, gas), Precious Metals (gold, silver), Industrial Metals (copper), Agriculture (wheat, corn), Livestock.<br><br>Trade via: Futures (most common), ETFs (GLD, USO), CFDs, Commodity stocks."},
{t:"Gold Trading Strategies",d:"20min",content:"<strong>What Moves Gold:</strong> Real interest rates (#1), USD strength (inverse), Geopolitical risk, Inflation, Central bank buying.<br><br>Key level: $2,000 (psychological). Best: Buy dips during risk-off periods. 4H and daily timeframes."},
{t:"Oil Trading",d:"20min",content:"<strong>WTI vs Brent.</strong> What moves oil: OPEC+ decisions (3-5% moves), Wednesday EIA inventory, geopolitics, demand, USD.<br><br>Seasonality: Summer driving (May-Aug), Winter heating (Dec-Feb), Refinery maintenance (Spring/Fall)."},
{t:"Copper as Economic Indicator",d:"15min",content:"<strong>'Dr. Copper'</strong> — Price diagnoses economic health. Used in construction, electronics, EVs. Rising = growth. Falling = slowdown.<br><br>Copper-Gold Ratio: Rising = risk-on. Falling = risk-off. Correlates with interest rates."},
{t:"Commodity Risk Management",d:"15min",content:"<strong>Specific Risks:</strong> Contango/backwardation (affects ETF returns), extreme volatility (5-10% daily), gap risk (OPEC, inventory data), seasonal patterns.<br><br>Position sizing: Max 3% risk per trade. Wider stops (2-3× ATR). Never trade futures without understanding margin."}
],
quiz:[{q:"Primary gold price driver:",opts:["Stock market","Real interest rates","Oil prices","Agriculture"],ans:1},{q:"Why 'Dr. Copper'?",opts:["It's expensive","Diagnoses economic health","Used in medicine","It's rare"],ans:1},{q:"Rising copper-gold ratio suggests:",opts:["Risk-off","Economic growth","Recession","Inflation"],ans:1}]},

{id:20,title:"Portfolio Construction",level:"advanced",icon:"🏗️",desc:"Build a portfolio matching your goals and risk tolerance.",duration:"2h 30min",modules:5,
lessons:[
{t:"Asset Allocation Principles",d:"20min",content:"<strong>Asset allocation = 90% of returns.</strong> Equities (highest return/risk), Fixed Income (income, lower volatility), Real Estate (inflation hedge), Commodities (diversification), Cash (safety).<br><br>Conservative: 40/50/10. Moderate: 60/30/10. Aggressive: 80/15/5."},
{t:"Modern Portfolio Theory",d:"20min",content:"<strong>Key:</strong> Diversification with low-correlation assets. Efficient Frontier = optimal return per risk level. Sharpe Ratio = risk-adjusted return (higher = better).<br><br>Stocks + Bonds: historically negative correlation. Gold + Stocks: low/negative. Two tech stocks: high positive (NOT diversification)."},
{t:"Rebalancing Strategies",d:"15min",content:"<strong>When:</strong> Calendar (quarterly/semi-annually), Threshold (drift > 5%), Combined (check quarterly, rebalance if > 5%).<br><br><strong>How:</strong> Sell overweight, buy underweight. Or direct new contributions to underweight (tax-efficient). Prefer rebalancing in tax-advantaged accounts."},
{t:"Factor Investing",d:"15min",content:"<strong>Factors:</strong> Value (low P/E, P/B), Momentum (trend following), Quality (high ROE, low debt), Size (small caps), Low Volatility (defensive).<br><br>ETFs: VTV/IWD (Value), MTUM (Momentum), QUAL (Quality), IWM (Size)."},
{t:"Tax-Efficient Investing",d:"15min",content:"<strong>Keep more of what you earn.</strong> Bonds in tax-advantaged accounts. Stocks in taxable (lower cap gains rates). Tax-loss harvesting. Hold > 1 year for long-term rates (0-20% vs up to 37%).<br><br><strong>Account Priority:</strong> 401(k) match → HSA → Roth IRA → remaining 401(k) → taxable brokerage."}
],
quiz:[{q:"Asset allocation determines what % of returns?",opts:["50%","70%","90%","30%"],ans:2},{q:"Sharpe Ratio measures:",opts:["Total return","Risk-adjusted return","Volatility","Correlation"],ans:1},{q:"Bonds should be in:",opts:["Taxable accounts","Tax-advantaged accounts","Crypto wallets","Cash"],ans:1}]},

{id:21,title:"Trading with Economic Data",level:"intermediate",icon:"📰",desc:"Turn economic releases into opportunities.",duration:"2h",modules:5,
lessons:[
{t:"The Economic Calendar",d:"15min",content:"<strong>High-Impact:</strong> FOMC (8x/year), NFP (monthly), CPI (monthly), GDP (quarterly).<br><br>Free calendars: ForexFactory.com, Investing.com, TradingEconomics.com."},
{t:"Trading Non-Farm Payrolls",d:"20min",content:"<strong>First Friday monthly, 8:30 AM ET.</strong> Strong NFP → USD up, stocks mixed. Weak → USD down, stocks may rally.<br><br>Strategies: Pre-NFP (reduce positions), Straddle (buy/sell stops), Wait & See (let initial spike settle 5-15 min). Never trade without stops."},
{t:"FOMC & Rate Decisions",d:"20min",content:"<strong>Most Important Event.</strong> Watch: Rate decision, Dot Plot (often more important), Statement language, Press conference tone.<br><br>Hawkish → USD up, stocks down, gold down. Dovish → opposite."},
{t:"CPI & Inflation Trading",d:"15min",content:"<strong>CPI = inflation measure.</strong> Core CPI (ex-food/energy) matters more to Fed. Higher than expected → rate hike fears. Lower → rate cut hopes.<br><br>First reaction often reversed. Wait 30 minutes before entering."},
{t:"Building a News Trading Plan",d:"15min",content:"<strong>5 Steps:</strong> (1) Check calendar. (2) Find consensus. (3) Plan scenarios. (4) Set alerts. (5) Execute or wait.<br><br>Never trade without stops during news. Reduce size 50%. Don't chase missed moves. Sometimes the best trade = no trade."}
],
quiz:[{q:"NFP is released:",opts:["Last Friday monthly","First Friday monthly","Every Monday","Quarterly"],ans:1},{q:"Fed's preferred CPI gauge:",opts:["Headline CPI","Core CPI","MoM CPI","YoY CPI"],ans:1},{q:"During FOMC, what often matters more than the decision?",opts:["Stock reaction","Gold price","Dot plot and statement","Bond yields"],ans:2}]},

{id:22,title:"TradingView & Charting Tools",level:"beginner",icon:"🖥️",desc:"Master tools professional traders use.",duration:"2h",modules:5,
lessons:[
{t:"TradingView Setup",d:"15min",content:"<strong>Most popular charting platform.</strong> Free tier excellent. Features: Multiple timeframes, 100+ indicators, drawing tools, price alerts, watchlists, community scripts."},
{t:"Setting Up Your Workspace",d:"20min",content:"<strong>Optimal Layout:</strong> Main chart (candlesticks + volume) + RSI + MACD + 20/50/200 MAs.<br><br>Templates: 'Trend Following' (MAs + ADX + RSI), 'Reversal' (Fib + RSI + BB), 'Breakout' (Volume + S/R + ATR).<br><br>Multi-TF: Daily (direction) + 4H (timing) + Watchlist."},
{t:"Screeners & Scanners",d:"15min",content:"<strong>Useful Scans:</strong> RSI < 30 (oversold), RSI > 70 (overbought), Price crossing 50 SMA, Volume > 2× avg, Near 52-week high.<br><br>Free alternatives: Finviz.com (heat maps), StockFetcher.com, Yahoo Finance."},
{t:"Alerts & Automation",d:"15min",content:"<strong>Set alerts, don't stare at charts.</strong> Price alerts at key levels, indicator alerts (RSI cross, MACD cross), drawing alerts (trendline touch), volume alerts.<br><br>Don't set too many — alert fatigue is real."},
{t:"Journal & Tracking",d:"15min",content:"<strong>Tools:</strong> Edgewonk ($169), TraderSync (free tier), Google Sheets (free), Notion.<br><br>Track: Win rate, avg win/loss, R:R, performance by setup/time/day, emotional state correlation."}
],
quiz:[{q:"Recommended default chart type:",opts:["Line","Bar","Candlestick","Area"],ans:2},{q:"Free screener with heat maps:",opts:["TradingView","Bloomberg","Finviz","Edgewonk"],ans:2},{q:"Why use alerts vs watching charts?",opts:["More fun","Saves time + reduces emotional decisions","More accurate","Charts are boring"],ans:1}]},

{id:23,title:"Algorithmic Trading Intro",level:"advanced",icon:"🤖",desc:"Automate strategies — from rules to Python trading bots.",duration:"2h 30min",modules:5,
lessons:[
{t:"What Is Algorithmic Trading?",d:"15min",content:"<strong>Types:</strong> Rule-Based (if/then), Statistical (mean reversion, pairs), Machine Learning, HFT (not for retail).<br><br>Advantages: No emotions, instant execution, backtestable, 24/7 monitoring."},
{t:"Building a Simple Bot",d:"20min",content:"<strong>Tools:</strong> Python 3.8+, ccxt (crypto) or alpaca-py (stocks), pandas + yfinance (data), backtrader or vectorbt (backtesting).<br><br>Simple RSI bot: If RSI < 30 → BUY. If RSI > 70 → SELL. Else HOLD."},
{t:"Backtesting Your Strategy",d:"20min",content:"<strong>Key Metrics:</strong> Total Return, Sharpe Ratio (> 1.0), Max Drawdown, Win Rate, Profit Factor (> 1.5).<br><br><strong>Mistakes:</strong> Look-ahead bias, Survivorship bias, Overfitting, Ignoring costs. Backtest on 5+ years of data."},
{t:"Paper Trading & Going Live",d:"15min",content:"<strong>Paper trade minimum 3 months.</strong> Compare to backtest. Start with minimum capital ($500-$1000). Stop-loss on every trade. Daily loss limit. Monitoring + kill switch."},
{t:"Risk & Ethics",d:"15min",content:"<strong>Risks:</strong> Bugs (catastrophic losses), API limits, Market impact, Regulatory (spoofing/layering illegal).<br><br><strong>The 3 AM Problem:</strong> Bot trading while you sleep. Always have: Max position limits, daily loss limits, auto-shutdown, phone alerts."}
],
quiz:[{q:"Biggest backtesting mistake:",opts:["Too much data","Overfitting","Too many strategies","Daily data"],ans:1},{q:"Forward-test before live:",opts:["1 week","1 month","3+ months","6+ months"],ans:2},{q:"Every bot needs:",opts:["Max leverage","Kill switch and loss limits","Only buy orders","No stops"],ans:1}]},

{id:24,title:"Margin Trading & Leverage",level:"advanced",icon:"⚖️",desc:"Understand margin before using it — power and peril.",duration:"2h",modules:5,
lessons:[
{t:"How Margin Works",d:"15min",content:"<strong>Margin = borrowing from broker.</strong> Key terms: Margin (collateral), Leverage (position/margin), Maintenance Margin (25-30% minimum), Margin Call (equity too low).<br><br>2:1 leverage, stock drops 50% → account wiped out. Without leverage → still have 50%."},
{t:"Smart Use of Leverage",d:"20min",content:"<strong>Makes Sense:</strong> Short-term high-conviction setups, diversification, low-vol strategies.<br><br><strong>Doesn't:</strong> Recovering losses, 'sure things', impatience, without stops.<br><br><strong>Safe Limits:</strong> Stocks 2:1, Forex 10:1, Crypto 3:1. Never use max available."},
{t:"Margin Call Scenarios",d:"15min",content:"<strong>2:1 leverage:</strong> 50% drop = wiped out. <strong>10:1 forex:</strong> 5% adverse = 50% account loss. 10% = gone.<br><br>What happens: Broker demands more funds. If not met, positions liquidated at market price. You can lose more than your deposit."},
{t:"Short Selling Mechanics",d:"20min",content:"<strong>Short = sell borrowed shares, buy back cheaper.</strong><br><br>Steps: Borrow shares → Sell at current price → Buy back lower → Return shares → Keep difference.<br><br><strong>Risks:</strong> Unlimited loss (stock can go to infinity). Margin requirements (150% initial). Hard to borrow (some stocks unavailable). Short squeeze (forced buying drives price up).<br><br><strong>Rules:</strong> Always use stop-loss. Max 2% risk. Don't short strong uptrends."},
{t:"Leverage Risk Calculator",d:"15min",content:"<strong>Formula:</strong> Max Loss % = Price Drop % × Leverage<br><br>5% drop at 2:1 = 10% account loss. 5% drop at 10:1 = 50% loss. 5% drop at 20:1 = 100% loss.<br><br><strong>Rule of Thumb:</strong> If your maximum tolerable loss is 20%, and the asset can move 5% against you, max leverage = 20/5 = 4:1."}
],
quiz:[{q:"2:1 leverage, 50% stock drop:",opts:["Lose 25%","Lose 50%","Account wiped out","Lose 100% of margin"],ans:2},{q:"Short selling has:",opts:["Limited loss","Unlimited loss risk","No risk","Same as long"],ans:1},{q:"Max leverage rule for forex beginners:",opts:["100:1","50:1","10:1","2:1"],ans:2}]},

{id:25,title:"Dividend Investing",level:"beginner",icon:"💰",desc:"Build passive income with dividend stocks and strategies.",duration:"2h",modules:5,
lessons:[
{t:"Why Dividend Investing?",d:"15min",content:"<strong>Dividends = cash payments from companies to shareholders.</strong><br><br>40% of S&P 500 historical returns came from dividends. Compound growth through reinvestment. Lower volatility than growth stocks. Income regardless of stock price."},
{t:"Dividend Metrics That Matter",d:"20min",content:"<strong>Key Metrics:</strong> Yield (annual dividend/price), Payout Ratio (dividends/earnings — want < 60%), Dividend Growth Rate (5-10% annually = healthy), Consecutive Years of Increases (Dividend Aristocrats = 25+ years).<br><br>⚠️ Yield > 6% often unsustainable. Check payout ratio."},
{t:"Dividend Aristocrats",d:"15min",content:"<strong>Companies that raised dividends 25+ consecutive years.</strong> Examples: J&J, Procter & Gamble, Coca-Cola, McDonald's, 3M.<br><br>Historical performance: Outperformed S&P 500 with lower volatility. NO has ever cut its dividend."},
{t:"DRIP — Dividend Reinvestment",d:"15min",content:"<strong>DRIP automatically reinvests dividends into more shares.</strong> Compound growth engine.<br><br>$10K invested at 3% yield + DRIP → After 30 years: $24,273 (with DRIP) vs $19,000 (without). That's $5,273 more from compounding."},
{t:"Building a Dividend Portfolio",d:"15min",content:"<strong>Target:</strong> 15-30 stocks across sectors. Yield: 2.5-4.5%. Dividend growth: 5-10% annually. Payout ratio: < 60%.<br><br>Review quarterly: Check payout ratios, dividend increases, sector balance. Rebalance annually."}
],
quiz:[{q:"What % of S&P 500 returns came from dividends historically?",opts:["10%","25%","40%","60%"],ans:2},{q:"Dividend Aristocrats raised dividends for:",opts:["10+ years","15+ years","25+ years","50+ years"],ans:2},{q:"Unsustainable dividend yield is typically:",opts:["< 2%","> 6%","3-4%","1%"],ans:1}]},

{id:26,title:"Market Cycles & Rotation",level:"advanced",icon:"🔄",desc:"Understand where we are in the cycle — and what outperforms next.",duration:"2h 30min",modules:5,
lessons:[
{t:"The Four Market Phases",d:"20min",content:"<strong>Accumulation:</strong> Smart money buying. Flat/down trend. Volume increasing. Sentiment bearish.<br><strong>Markup:</strong> Uptrend. Higher highs/lows. Volume strong. Sentiment improving.<br><strong>Distribution:</strong> Smart money selling. Price stalling. Volume on sell-off. Sentiment euphoric.<br><strong>Markdown:</strong> Downtrend. Lower highs/lows. Volume on decline. Sentiment panicking."},
{t:"Sector Rotation Model",d:"20min",content:"<strong>Early Cycle:</strong> Financials, Real Estate, Consumer Discretionary. <strong>Mid Cycle:</strong> Technology, Industrials. <strong>Late Cycle:</strong> Energy, Materials. <strong>Recession:</strong> Consumer Staples, Healthcare, Utilities.<br><br>Rotation typically leads economic data by 6-9 months."},
{t:"Economic Cycle Indicators",d:"15min",content:"<strong>Leading:</strong> Yield curve (inversion = recession), PMI, Building permits, Consumer expectations.<br><strong>Coincident:</strong> GDP, Employment, Industrial production.<br><strong>Lagging:</strong> Unemployment rate, CPI, Interest rates."},
{t:"Yield Curve Analysis",d:"20min",content:"<strong>Normal:</strong> Long rates > Short rates. Healthy economy.<br><strong>Flat:</strong> Rates similar. Transition period.<br><strong>Inverted:</strong> Short > Long. Recession signal (has predicted every recession since 1960 with one false signal).<br><br>Current curve shape tells you where we are in the cycle."},
{t:"Positioning for the Next Phase",d:"15min",content:"<strong>Strategy:</strong> Identify current phase → Position for NEXT phase.<br><br>If early cycle → Buy financials, discretionary. If mid → Rotate to tech, industrials. If late → Energy, materials, defensive. If recession → Staples, healthcare, utilities, bonds, gold.<br><br>The biggest profits go to those who position early."}
],
quiz:[{q:"Smart money is buying during which phase?",opts:["Markup","Distribution","Accumulation","Markdown"],ans:2},{q:"Which sector outperforms in recession?",opts:["Technology","Consumer Discretionary","Consumer Staples","Financials"],ans:2},{q:"Yield curve inversion has predicted recessions with how many false signals?",opts:["None","One","Three","Five"],ans:1}]},

{id:27,title:"Trading Plan Development",level:"intermediate",icon:"📝",desc:"Create a written trading plan — your roadmap to consistency.",duration:"2h",modules:5,
lessons:[
{t:"Why You Need a Trading Plan",d:"15min",content:"<strong>A trading plan eliminates emotional decisions.</strong> Without one, you're gambling.<br><br>Traders with plans are 2-3× more likely to be profitable. The plan makes decisions BEFORE you're emotional. It's your contract with yourself."},
{t:"Defining Your Trading Style",d:"20min",content:"<strong>Choose Based on:</strong><br>Available time (Day trading = full time. Swing = 30 min/day. Position = 15 min/week).<br>Capital (Day = $25K+. Swing = $5K+. Position = $1K+).<br>Personality (Patient? Position. Action-oriented? Day. Balanced? Swing).<br>Risk tolerance (Day = highest risk. Position = lowest)."},
{t:"Creating Entry & Exit Rules",d:"20min",content:"<strong>Entry Rules:</strong> Setup criteria (S/R + indicator + candlestick confirmation). Timeframe alignment. Volume confirmation. No entry without stop-loss.<br><br><strong>Exit Rules:</strong> Stop-loss placement (technical, not arbitrary). Take-profit levels (at least 1:2 R:R). Trailing stop rules. Time-based exit. News event exit."},
{t:"Money Management Rules",d:"15min",content:"<strong>Essential Rules:</strong> Max 1-2% risk per trade. Max 5-6% open risk. Max 3% daily loss. Max 6% weekly loss. Position sizing formula. Correlation limits. Minimum R:R requirements."},
{t:"Review & Optimization",d:"15min",content:"<strong>Weekly Review:</strong> Did I follow my plan? What mistakes? What worked? Any rule violations? Adjustments needed?<br><br><strong>Monthly:</strong> Performance stats (win rate, avg R:R, Sharpe). Strategy comparison. Journal patterns.<br><br><strong>Rule:</strong> Don't change strategy during losing streaks. Change only during objective review periods."}
],
quiz:[{q:"Traders with plans are how much more likely to be profitable?",opts:["Same","1.5×","2-3×","5×"],ans:2},{q:"What's the minimum R:R requirement?",opts:["1:1","1:1.5","1:2","1:3"],ans:2},{q:"When should you change your strategy?",opts:["After 3 losses","During losing streaks","Only during objective review periods","Never"],ans:2}]},

{id:28,title:"Global Markets & Diversification",level:"intermediate",icon:"🌍",desc:"Think globally — diversify across countries, currencies, and asset classes.",duration:"2h",modules:5,
lessons:[
{t:"Why Global Diversification Matters",d:"15min",content:"<strong>Don't put all eggs in one country.</strong> US = ~60% of global market cap but not always the best performer. International stocks outperformed US in 2000-2010. Currency diversification. Different economic cycles.<br><br>Home country bias = unrecognized concentration risk."},
{t:"Major Global Markets",d:"20min",content:"<strong>US:</strong> Largest, most liquid. S&P 500, NASDAQ. <strong>Europe:</strong> Stoxx 600, DAX, FTSE. Dividend-focused. <strong>Japan:</strong> Nikkei, TOPIX. Value + dividend. <strong>China:</strong> SSE, Hang Seng. Growth but regulatory risk. <strong>Emerging:</strong> Brazil, India, SE Asia. Highest growth potential.<br><br>ETFs: VEU (ex-US), VXUS (international), VWO (emerging), EWJ (Japan), FXI (China)."},
{t:"Currency Risk & Hedging",d:"15min",content:"<strong>When you buy foreign stocks, you also buy foreign currency.</strong><br><br>Strong USD → International returns reduced. Weak USD → International returns boosted.<br><br>Hedged ETFs (e.g., HEFA vs EFA) remove currency risk. Decide if you want currency exposure or not."},
{t:"ADR & International Trading",d:"15min",content:"<strong>ADRs (American Depositary Receipts)</strong> let you buy foreign stocks on US exchanges. Levels: I (OTC, less info), II (listed, more disclosure), III (IPO, full disclosure).<br><br>Alternatives: International ETFs (easiest), Direct buying (need international broker), Country funds."},
{t:"Building a Global Portfolio",d:"15min",content:"<strong>Sample Allocation:</strong> 50% US, 20% Developed International, 10% Emerging Markets, 10% International Bonds, 10% Gold/Commodities.<br><br>Rebalance when drift > 5%. Consider tax implications of foreign dividends (foreign tax credit available)."}
],
quiz:[{q:"US is approximately what % of global market cap?",opts:["30%","45%","60%","80%"],ans:2},{q:"Strong USD does what to international returns?",opts:["Boosts them","Reduces them","No effect","Doubles them"],ans:1},{q:"ADRs allow:",opts:["Buying foreign stocks on US exchanges","Trading currencies","Buying crypto","Short selling"],ans:0}]},

{id:29,title:"Trading Discipline & Habits",level:"beginner",icon:"🎯",desc:"Build the habits that separate consistent winners from everyone else.",duration:"2h",modules:5,
lessons:[
{t:"The Daily Trading Routine",d:"15min",content:"<strong>Pre-Market (30 min before open):</strong> Check overnight news, scan for setups, set alerts, review economic calendar, determine bias.<br><br><strong>During Market:</strong> Execute plan. No deviations. Take breaks every 90 min.<br><br><strong>Post-Market:</strong> Journal all trades. Review decisions. Prepare for tomorrow."},
{t:"Building Consistency",d:"20min",content:"<strong>Consistency > Perfection.</strong> Trade the same setup every time. Same risk. Same process. Results will follow.<br><br><strong>The 3 C's:</strong> Consistency (same process), Conviction (only high-probability setups), Control (manage risk and emotions).<br><br>Track your consistency score: What % of trades followed your plan? Aim for 90%+."},
{t:"Handling Losing Streaks",d:"15min",content:"<strong>Every trader has losing streaks. It's normal.</strong><br><br><strong>Protocol:</strong> (1) Acknowledge it. (2) Review — are you following the plan? (3) If yes → it's variance. Stay the course. (4) If no → Fix the violations. (5) Reduce size by 50%. (6) Take a 1-2 day break if needed.<br><br>Never increase size during a losing streak. That's how accounts blow up."},
{t:"The 80/20 of Trading",d:"15min",content:"<strong>80% of profits come from 20% of trades.</strong> The best traders are patient. They wait for A+ setups and pass on everything else.<br><br><strong>Your Edge:</strong> Not in having more trades, but in having better ones. One great trade > ten mediocre ones. Quality > Quantity."},
{t:"Long-Term Success Mindset",d:"15min",content:"<strong>Trading is a marathon, not a sprint.</strong><br><br>Year 1: Learn, lose small, build habits. Year 2: Break even, refine strategy. Year 3+: Consistently profitable.<br><br>Focus on: Process (not outcomes). Learning (not earning). Improvement (not perfection). Survival (not home runs).<br><br>The traders who succeed are the ones who didn't quit."}
],
quiz:[{q:"What % of trades should follow your plan?",opts:["50%","70%","90%+","100%"],ans:2},{q:"During a losing streak, you should:",opts:["Increase size","Change strategy","Reduce size and review","Trade more aggressively"],ans:2},{q:"How long does it typically take to become consistently profitable?",opts:["1 month","6 months","1-2 years","5+ years"],ans:2}]},

{id:30,title:"Advanced Risk: Options, Margin & Leverage",level:"advanced",icon:"⚙️",desc:"Master the complex risk tools — or they'll master you.",duration:"2h 30min",modules:5,
lessons:[
{t:"Portfolio-Level Risk Management",d:"20min",content:"<strong>Beyond single trades:</strong> Total portfolio risk, correlation between positions, sector concentration, drawdown management, tail risk (black swan events).<br><br>Target: Max 20% drawdown. If hit, reduce all positions by 50% until recovery. Always have 10-20% cash for opportunities."},
{t:"Options Greeks for Risk",d:"20min",content:"<strong>Greek Risk Management:</strong><br>Delta-neutral strategies (iron condors, butterflies). Gamma risk near expiration. Theta decay — selling options = theta works for you. Vega risk — IV changes can wipe out directional gains.<br><br>Position Greeks: Know your portfolio's total delta, gamma, theta, vega exposure."},
{t:"Margin Optimization",d:"15min",content:"<strong>Margin Efficiency:</strong> Use margin for diversification, not concentration. Cross-margining (use stock margin for options hedging). Portfolio margin (15% requirement vs 25% Reg T — available for accounts > $100K).<br><br>Never use > 50% of available margin. Keep maintenance buffer."},
{t:"Hedging Strategies",d:"20min",content:"<strong>Protect Your Portfolio:</strong><ul><li><strong>Protective Puts</strong> — Insurance on individual positions</li><li><strong>Put Spreads on Index</strong> — Cheaper portfolio insurance</li><li><strong>VIX Calls</strong> — Profit from volatility spikes</li><li><strong>Gold/ Bonds</strong> — Natural hedges for equity portfolios</li><li><strong>Inverse ETFs</strong> — Simple hedging without margin</li></ul><br>Hedging costs money (like insurance). Budget 1-2% annually for portfolio protection."},
{t:"Risk Management Technology",d:"15min",content:"<strong>Tools:</strong> Risk dashboards (thinkorswim, Interactive Brokers), Correlation matrices, VaR (Value at Risk) calculations, Stress testing (what if 2008 happens again?), Position sizing calculators, Automated stop-losses.<br><br><strong>Daily Risk Check:</strong> Total exposure, correlation risk, upcoming events, margin utilization, cash buffer."}
],
quiz:[{q:"Max recommended portfolio drawdown:",opts:["5%","10%","20%","50%"],ans:2},{q:"Theta works in your favor when:",opts:["Buying options","Selling options","Holding stock","Trading futures"],ans:1},{q:"Annual budget for portfolio hedging:",opts:["0%","0.5%","1-2%","5%"],ans:2}]}
];
